window.chineseSwitcher={twContent:null,cnContent:null,converter:null,init:function(){window.OpenCC?(this.converter=OpenCC.Converter({from:"tw",to:"cn"}),this.initSwitcher()):(console.log("等待 OpenCC 載入..."),setTimeout(()=>this.init(),100))},initSwitcher:function(){const e=document.querySelector("article");if(!e)return;this.twContent=e.innerHTML;const n=document.querySelector('[data-lang="zh-tw"]'),t=document.querySelector('[data-lang="zh-cn"]');if(!n||!t)return;t.addEventListener("click",()=>{if(t.classList.contains("active"))return;if(n.classList.contains("active")&&(this.twContent=e.innerHTML),this.cnContent)e.innerHTML=this.cnContent;else{const n=e.cloneNode(!0),s=document.createTreeWalker(n,NodeFilter.SHOW_TEXT,null,!1),t=[];for(;s.nextNode();)t.push(s.currentNode);for(let e=t.length-1;e>=0;e--){const n=t[e];n.textContent.trim()&&(n.textContent=this.converter(n.textContent))}this.cnContent=n.innerHTML,e.innerHTML=this.cnContent}t.classList.add("active"),n.classList.remove("active"),localStorage.setItem("preferredChinese","cn")}),n.addEventListener("click",()=>{if(n.classList.contains("active"))return;t.classList.contains("active")&&(this.cnContent=e.innerHTML),e.innerHTML=this.twContent,n.classList.add("active"),t.classList.remove("active"),localStorage.setItem("preferredChinese","tw")});const s=localStorage.getItem("preferredChinese");s==="cn"&&t.click(),console.log("繁簡切換初始化完成")},updateContent:function(e,t){e==="tw"?this.twContent=t:e==="cn"&&(this.cnContent=t)}}